INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 1, 'What is a Computer?', 'Parts of a Computer, Turning It On and Off', 'This class introduces you to what a computer actually is and what its different parts do. You''ll learn the names of each piece, how to safely turn your computer on and off, and feel confident sitting down at a computer for the first time.', '[{"title":"What Is a Computer, Really?","content":"A computer is just a machine that helps you do things like write letters, look at photos, and talk to family. Think of it like a really smart typewriter mixed with a TV and a telephone. We''ll look at the difference between a desktop computer (the kind that sits on a desk) and a laptop (the kind you can carry around)."},{"title":"The Parts You Can See and Touch","content":"Let''s learn the names of the parts. The monitor is your screen, like a TV. The keyboard is where you type, like a typewriter. The mouse is a little device you move with your hand to point at things on the screen. If you have a laptop, all of these are built into one piece. We''ll point to each part and say its name together."},{"title":"Turning Your Computer On and Off Safely","content":"To turn on your computer, you press the power button, which usually has a little circle with a line through the top. Turning it off is important too. You don''t just unplug it! We''ll learn how to shut it down properly using the Start menu so nothing gets lost or broken."},{"title":"What Happens When It Starts Up","content":"When you turn on your computer, it takes a moment to wake up, just like you do in the morning. You''ll see a loading screen, and then your desktop appears. That''s your home base. Don''t worry if it takes a minute. Your computer is just getting ready for you."}]', '["Identify the main parts of a computer by name (monitor, keyboard, mouse, power button)","Safely turn a computer on and shut it down properly","Understand the difference between a desktop and a laptop computer"]', '[{"title":"Name That Part","description":"Look at the computer in front of you. Point to and name each part out loud: the monitor, the keyboard, the mouse, and the power button. If you are using a laptop, find where each of these is built in.","type":"hands-on"},{"title":"Power On and Shut Down Practice","description":"Practice turning your computer on by pressing the power button. Once it starts up, practice shutting it down properly using the Start menu. Do this two times so it feels natural.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about what a computer is and its basic parts. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 15);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 2, 'Using a Mouse and Keyboard', 'Click, Double-Click, Right-Click, and Typing Basics', 'This class teaches you how to use the two most important tools for controlling your computer: the mouse and the keyboard. You''ll practice clicking, moving the pointer, and typing letters and numbers with confidence.', '[{"title":"Holding and Moving the Mouse","content":"Rest your hand gently on the mouse, like you''re holding a small bar of soap. When you move the mouse on your desk, a little arrow called the pointer moves on your screen. Try sliding the mouse around and watch the pointer follow. Don''t squeeze too hard. Nice and relaxed."},{"title":"Clicking, Double-Clicking, and Right-Clicking","content":"The left button on the mouse is your main button. One click selects something, like pointing at it and saying I want that. A double-click (two quick taps) opens something. The right button gives you a little menu of extra options. Don''t worry about memorizing this. We''ll practice each one."},{"title":"Getting to Know the Keyboard","content":"The keyboard looks like a lot of buttons, but you only need a few to get started. The letter keys work just like a typewriter. The space bar at the bottom adds a space between words. The Enter key moves you to a new line. The Backspace key erases the last letter you typed, like a little undo button."},{"title":"Typing Your First Words","content":"We''ll open a simple program and practice typing your name, your address, and a short sentence. Take your time. There is no rush. If you make a mistake, just press Backspace and try again. The more you practice, the easier it gets."}]', '["Move the mouse pointer smoothly across the screen to a specific spot","Perform a single click, double-click, and right-click correctly","Type a short sentence using the keyboard including spaces and backspace"]', '[{"title":"Mouse Target Practice","description":"Move your mouse pointer to different icons on the screen. Practice single-clicking on one, double-clicking on another, and right-clicking on a third. Take your time and repeat until it feels comfortable.","type":"hands-on"},{"title":"Type About Yourself","description":"Open Notepad or a similar program. Type your full name, your favorite food, and one sentence about something you enjoy. Use the space bar, Enter key, and Backspace key as you go.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about using a mouse and keyboard. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 3, 'Understanding the Desktop', 'Icons, Taskbar, and the Start Menu', 'This class helps you understand what you see on the screen when your computer is ready to use. You''ll learn what the desktop is, what those little pictures called icons mean, and how to use the taskbar and Start menu to find what you need.', '[{"title":"Welcome to Your Desktop","content":"When your computer finishes starting up, you see the desktop. Think of it like the top of a real desk. It''s your home base where you can see your stuff and start working. The background picture is just decoration, like a photo on your wall. Everything else on the screen is there to help you."},{"title":"What Are Those Little Pictures?","content":"The small pictures on your desktop are called icons. Each one is a shortcut to a program or a file. Double-click on one to open it. For example, you might see a trash can icon where deleted items go, or an icon for the internet browser. Think of icons like labeled drawers in a filing cabinet."},{"title":"The Taskbar at the Bottom","content":"The strip along the bottom of your screen is the taskbar. It shows you what programs are currently open, just like seeing which books are open on your desk. You can click on any item in the taskbar to switch to that program. You''ll also see the clock and date on the right side."},{"title":"Using the Start Menu","content":"The Start button is usually in the bottom left corner. Click it to see a menu of all the programs on your computer. It''s like opening a drawer full of tools. You can search for a program by typing its name, or you can scroll through the list. This is how you find everything on your computer."}]', '["Identify what the desktop, icons, and taskbar are and what they do","Open the Start menu and find a program by scrolling or searching","Switch between open programs using the taskbar"]', '[{"title":"Desktop Scavenger Hunt","description":"Look at your desktop and count how many icons you see. Try to guess what three of them do based on their pictures and names. Then double-click one to see if you were right.","type":"hands-on"},{"title":"Start Menu Exploration","description":"Click the Start button and find three programs: a calculator, a notepad, and the settings. Try opening each one and then find them on the taskbar at the bottom of the screen.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about the computer desktop, icons, and the taskbar. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 15);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 4, 'Opening and Closing Programs', 'How to Find and Use Applications', 'This class teaches you how to open programs (also called applications or apps) on your computer and how to close them when you are done. You''ll learn several ways to find and start programs and understand why closing them properly matters.', '[{"title":"What Is a Program?","content":"A program is a tool that lets you do something on your computer. A calculator program does math. A word processing program lets you write letters. A web browser lets you look at the internet. You might also hear people say app or application. They all mean the same thing."},{"title":"Opening a Program from the Desktop","content":"If you see an icon on your desktop for the program you want, just double-click on it and it will open up. Think of it like opening a book. If you don''t see the icon, don''t worry. We have other ways to find it."},{"title":"Finding Programs in the Start Menu","content":"Click the Start button in the bottom-left corner. You can scroll through the list to find the program you want, or you can type the name of the program in the search box at the top. This is like looking up a name in a phone book. Try typing calculator and see what comes up."},{"title":"Closing a Program Properly","content":"When you are done with a program, close it by clicking the X button in the top-right corner of the window. This is important because leaving too many programs open can slow your computer down, like having too many appliances plugged in at once. Always save your work before closing."}]', '["Open a program using a desktop icon and from the Start menu","Search for a specific program by typing its name","Close a program properly using the X button"]', '[{"title":"Open Three Programs","description":"Open three different programs: one from a desktop icon, one by searching the Start menu, and one by scrolling through the Start menu. Notice how each one appears on the taskbar when it opens.","type":"hands-on"},{"title":"Close Them All","description":"Now close each of the three programs by clicking the X button in the top-right corner. Watch the taskbar to confirm they are gone. Practice this until you feel comfortable.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about opening and closing programs on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 15);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 5, 'Creating and Saving Files', 'Documents, Where They Go, and Naming Them', 'This class teaches you how to create something on your computer and save it so you can find it later. You''ll learn what a file is, how to give it a name, and where your computer stores your work.', '[{"title":"What Is a File?","content":"A file is anything you create or save on your computer. A letter you type is a file. A photo is a file. A file is like a piece of paper you put in a folder. Every file needs a name so you can find it again later, just like labeling a folder in a filing cabinet."},{"title":"Creating Your First File","content":"Let''s open Notepad, which is a very simple writing program. Type a short message like Dear Family, I am learning to use the computer! That''s it. You have just created something on your computer. Now we need to save it so it doesn''t disappear when you close the program."},{"title":"Saving Your Work","content":"To save your file, go to the top of the screen and click File, then click Save As. A box will pop up asking you two things: what do you want to name it, and where do you want to put it. Type a name like My First Letter and save it to the Desktop or Documents folder. Now it''s safe."},{"title":"Finding Your Saved File Later","content":"After you save a file, you can find it again. If you saved it to the Desktop, you''ll see it right there when you close everything. If you saved it to Documents, you can open the Documents folder from the Start menu. Think of it like putting a letter in a specific drawer so you know where to look."}]', '["Create a new file by typing text in a simple program","Save a file with a clear name to a specific location","Find and reopen a file that was previously saved"]', '[{"title":"Write and Save a Note","description":"Open Notepad and type a short grocery list or a note to yourself. Save it to the Desktop with a name like My Grocery List. Then close Notepad and find the file on your Desktop. Double-click it to open it again.","type":"hands-on"},{"title":"Save to Two Places","description":"Create another short note and save it to the Documents folder. Then create a third note and save it to the Desktop. Practice finding both files in their locations.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about creating and saving files on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 6, 'Organizing Your Files', 'Folders, Moving Files, and Finding Things', 'This class teaches you how to keep your computer tidy by organizing your files into folders. You''ll learn how to create folders, move files into them, and find things quickly when you need them.', '[{"title":"Why Organization Matters","content":"Imagine if you threw every piece of mail, every photo, and every bill into one big pile on the floor. It would be very hard to find anything. Your computer works the same way. If you save everything in one place without organizing it, you''ll have a hard time finding what you need. Folders help you sort things out."},{"title":"Creating a Folder","content":"A folder on your computer is just like a folder in a filing cabinet. To create one, right-click on an empty spot on your Desktop, then choose New, then Folder. A new folder will appear. Type a name for it like My Letters or Family Photos and press Enter. Now you have a place to put things."},{"title":"Moving Files into Folders","content":"To put a file into a folder, click on the file once to select it. Then hold down the mouse button and drag it on top of the folder, then let go. The file is now inside the folder. You can also right-click the file, choose Cut, open the folder, and right-click inside and choose Paste. Both ways work just fine."},{"title":"Finding Files When You Need Them","content":"If you forget where you put something, use the search feature. Click the Start button and type the name of the file. Your computer will look for it and show you where it is. You can also open File Explorer, which shows you all your folders and files like a map of a building with rooms and drawers."}]', '["Create a new folder and give it a descriptive name","Move a file from the Desktop into a folder","Use the search feature to find a file on the computer"]', '[{"title":"Build Your Filing System","description":"Create three folders on your Desktop: one called Letters, one called Lists, and one called Fun Stuff. Then move any files you created in previous classes into the right folder.","type":"hands-on"},{"title":"Search and Find","description":"Close all your folders. Now use the Start menu search to find one of the files you saved earlier. Type part of its name and see if the computer can find it for you. Try this with two different files.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about organizing files and folders on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 7, 'Understanding Windows and Screens', 'Minimize, Maximize, Resize, and Switch Between Programs', 'This class teaches you how to work with the windows that open on your screen. You''ll learn how to make windows bigger, smaller, move them around, and switch between multiple programs at once.', '[{"title":"What Is a Window?","content":"When you open a program, it appears in a rectangle on your screen called a window. It''s called a window because it''s like looking through a window at your work. You can have multiple windows open at once, just like having several books open on your desk at the same time."},{"title":"The Three Buttons in the Corner","content":"In the top-right corner of every window, you''ll see three small buttons. The line button (minimize) hides the window but keeps it running. The square button (maximize) makes the window fill the whole screen. The X button closes the window. Think of minimize as putting a book face-down on the desk. Maximize is like spreading it out flat."},{"title":"Resizing and Moving Windows","content":"You can make a window any size you want. Hover your mouse over the edge of the window until the pointer changes shape, then click and drag to resize it. To move a window, click on the bar at the very top of the window and drag it wherever you want. It''s like sliding a piece of paper around on your desk."},{"title":"Switching Between Windows","content":"If you have more than one window open, you can switch between them by clicking on the program''s icon in the taskbar at the bottom. You can also hold the Alt key and tap the Tab key to see all your open windows and pick one. This is useful when you want to look at two things at the same time."}]', '["Minimize, maximize, and restore a window using the corner buttons","Resize a window by dragging its edges","Switch between two open programs using the taskbar"]', '[{"title":"Window Gymnastics","description":"Open Notepad and the Calculator. Practice minimizing Notepad, then bringing it back by clicking on it in the taskbar. Maximize the Calculator, then restore it to a smaller size. Move both windows around the screen.","type":"hands-on"},{"title":"Side by Side","description":"Open two programs at the same time. Resize them so they sit next to each other on the screen, each taking up half. Practice switching between them using the taskbar and using Alt plus Tab.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about managing windows and screens on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 15);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 8, 'Basic Settings and Personalization', 'Wallpaper, Text Size, Brightness, and Volume', 'This class shows you how to make your computer more comfortable and personal. You''ll learn how to change the background picture, make text bigger so it''s easier to read, adjust the screen brightness, and control the volume.', '[{"title":"Making Your Computer Feel Like Yours","content":"Your computer doesn''t have to look the same way it did when you first turned it on. Just like you can rearrange furniture in your house, you can change how your computer looks and feels. These changes are found in a place called Settings, and they are easy and fun to explore."},{"title":"Changing Your Wallpaper","content":"The picture behind everything on your desktop is called the wallpaper. You can change it to a photo of your grandkids, a pretty landscape, or anything you like. Go to Settings, then Personalization, then Background. You can pick from the choices or use your own photo. It''s like hanging a new picture on your wall."},{"title":"Making Text Bigger and Easier to Read","content":"If the text on your screen is too small, you can make it bigger. Go to Settings, then Display, and look for the scale or text size option. Slide it up to make everything larger. You can also hold the Ctrl key and scroll your mouse wheel to zoom in on web pages. Don''t strain your eyes when there''s an easy fix."},{"title":"Adjusting Brightness and Volume","content":"If your screen is too bright or too dim, you can adjust the brightness. On a laptop, there are usually brightness keys near the top of the keyboard with little sun icons. You can also change it in Settings under Display. For volume, look for the speaker icon near the clock on the taskbar. Click it and slide to make sound louder or quieter."}]', '["Change the desktop wallpaper to a new image","Increase the text size to make reading easier","Adjust the screen brightness and system volume"]', '[{"title":"Redecorate Your Desktop","description":"Go to Settings and change your wallpaper to something you like. Then increase the text size by one or two steps and see how it looks. Change it back if you want, or keep it bigger.","type":"hands-on"},{"title":"Sound and Light Check","description":"Find the volume control on the taskbar and adjust it up and down. Then find the brightness setting and adjust it to a comfortable level. Make a note of what settings feel best for you.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about basic settings and personalization on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 15);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 9, 'Printing Basics', 'Connecting a Printer and Printing a Document', 'This class teaches you how to connect a printer to your computer and print things out. You''ll learn how to print a letter, choose how many copies you want, and what to do if something doesn''t work right.', '[{"title":"Why Printing Still Matters","content":"Even though so much is done on screens now, there are still times when you need something on paper. Medical forms, recipes, photos for the fridge, letters to friends. Printing gives you a physical copy you can hold, mail, or put on the wall. Let''s learn how to do it."},{"title":"Connecting Your Printer","content":"Most printers today connect to your computer through a USB cable or through your Wi-Fi. If it uses a cable, just plug one end into the printer and the other into your computer. If it connects by Wi-Fi, your computer will find it automatically in most cases. Go to Settings, then Devices, then Printers to see if your printer shows up."},{"title":"Printing Your First Document","content":"To print something, open the file you want to print. Then click File at the top of the program and choose Print. A box will pop up where you can choose which printer to use, how many copies you want, and whether to print all pages or just some. Then click the Print button and your document will come out of the printer."},{"title":"Troubleshooting Printing Problems","content":"Sometimes printing doesn''t work the first time. Check that the printer is turned on and has paper in it. Make sure the right printer is selected in the print window. If nothing happens, try turning the printer off and back on. Don''t worry if it takes a couple tries. Even experienced computer users have printer trouble sometimes."}]', '["Connect a printer to the computer or verify it is already connected","Print a document by choosing File then Print","Select the number of copies and the correct printer before printing"]', '[{"title":"Print a Practice Page","description":"Open one of the files you created in a previous class. Click File, then Print. Make sure the right printer is selected, set the copies to one, and press Print. Walk over to the printer and collect your page.","type":"hands-on"},{"title":"Print Multiple Copies","description":"Open another document and print two copies of it. Check the printer to make sure both copies came out. If something doesn''t work, try the troubleshooting steps we learned.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about printing documents from a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 10, 'Getting Help When Stuck', 'Built-in Help, Restarting, and Asking for Support', 'This class teaches you what to do when something goes wrong or you don''t know how to do something on your computer. You''ll learn how to use built-in help, when to restart, and how to ask someone for help without feeling embarrassed.', '[{"title":"Everyone Gets Stuck Sometimes","content":"First, let''s get something important out of the way. Everyone gets stuck on the computer sometimes, even people who have been using them for years. There is nothing wrong with not knowing something. The fact that you are learning right now is wonderful. Let''s talk about what to do when you hit a bump in the road."},{"title":"Using Built-in Help","content":"Most programs have a Help option in the menu at the top. You can also press the F1 key on your keyboard, which often opens a help page. Windows also has a search bar where you can type a question like how do I change my password and it will try to find the answer for you. It''s like having a reference book built right in."},{"title":"The Magic of Restarting","content":"If your computer is acting funny, slow, or frozen, the best first step is to restart it. Click the Start button, then the power icon, then Restart. This clears out any little problems and gives your computer a fresh start. It''s like a good night''s sleep for your computer. You''d be amazed how many problems this fixes."},{"title":"Asking for Help the Right Way","content":"If you need to ask someone for help, try to describe what you see on the screen and what you were trying to do. For example, I was trying to save a file and a box popped up that says error. That helps the person understand your problem. Never be afraid to ask for help. That''s what family, friends, and tech support are there for."}]', '["Use the built-in help or search feature to look up a question","Restart the computer properly when something isn''t working","Describe a computer problem clearly enough to ask someone for help"]', '[{"title":"Help Yourself","description":"Pick a question you have about the computer, like how do I make text bold or how do I change the time. Type it into the Windows search bar and see what comes up. Try the F1 key in an open program to see its help page.","type":"hands-on"},{"title":"Practice Restarting","description":"Click the Start button, then the power icon, and choose Restart. Watch the computer shut down and start back up again. Time how long it takes. Notice that everything you had open before is closed, so always save your work first.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about getting help when stuck on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 15);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 1, 'Introduction to Web Browsers', 'Chrome, Edge, Firefox, and What They Do', 'This class introduces you to web browsers, the programs you use to explore the internet. You''ll learn what a browser is, how to open one, and how to visit websites by typing in an address or clicking a link.', '[{"title":"What Is a Web Browser?","content":"A web browser is the program you use to look at the internet. Think of the internet as a giant library, and the browser is the door that lets you walk in. The most common browsers are Google Chrome, Microsoft Edge, and Mozilla Firefox. They all do the same basic thing, just like different brands of cars all get you where you need to go."},{"title":"Opening Your Browser and Visiting a Website","content":"To open your browser, find its icon on the Desktop or in the Start menu and click on it. Once it opens, you''ll see a long box at the top called the address bar. This is where you type the address of a website, like www.google.com. Press Enter and the website will load. It''s like dialing a phone number to reach someone."},{"title":"Understanding Links and Navigation","content":"When you are on a website, you''ll see words or pictures that change your pointer to a little hand when you hover over them. These are called links, and clicking them takes you to another page. The back arrow button in the top-left corner takes you back to the previous page. It''s like flipping pages in a magazine and being able to flip back."},{"title":"Tabs and Bookmarks","content":"If you want to look at more than one website at a time, you can open a new tab by clicking the little plus sign next to the current tab. Each tab is like having another book open on your desk. If you find a website you want to come back to later, you can bookmark it, which saves the address so you don''t have to type it again."}]', '["Open a web browser and type in a website address to visit a specific page","Use the back button and click links to navigate between web pages","Open a new tab and bookmark a favorite website"]', '[{"title":"Visit Three Websites","description":"Open your browser and visit three websites by typing their addresses: www.google.com, www.weather.com, and www.wikipedia.org. Use the back button to go back to each one. Notice how the address bar changes with each page.","type":"hands-on"},{"title":"Tabs and Bookmarks Practice","description":"Open three tabs in your browser, one for each website above. Switch between them by clicking the tabs at the top. Then bookmark your favorite one so you can find it easily next time.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about web browsers and visiting websites. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 2, 'Searching the Internet Effectively', 'Google Search Tips and Finding What You Need', 'This class teaches you how to use a search engine like Google to find information on the internet. You''ll learn how to type good searches, understand what comes back, and tell the difference between helpful results and advertisements.', '[{"title":"What Is a Search Engine?","content":"A search engine is a tool that looks through the entire internet to find what you are looking for. Google is the most popular one. Think of it like a librarian who can search through billions of books in less than a second. You type in what you want to know, and it shows you a list of pages that might have the answer."},{"title":"How to Type a Good Search","content":"The key to getting good results is typing clear, specific words. Instead of typing food, try typing easy chicken soup recipe. Instead of typing doctor, try typing family doctor near me. Use the words you would use to describe what you need to a friend. You don''t need full sentences. A few clear words work best."},{"title":"Reading Your Search Results","content":"After you search, you''ll see a list of results. Each one has a title in blue (which you can click), a web address underneath, and a short description. The top results are usually the most helpful, but watch out for results that say Ad next to them. Those are advertisements, not the best answers. Scroll down a little to find the real results."},{"title":"Searching for Specific Things","content":"You can search for almost anything. Try typing weather in your city name to see the forecast. Type a recipe name to find instructions. Type a question like how tall is the Statue of Liberty and Google will often show you the answer right at the top. The internet is full of information, and searching is how you find it."}]', '["Type a clear and specific search into Google to find information","Identify the difference between regular search results and advertisements","Use Google to find the answer to a specific everyday question"]', '[{"title":"Answer Five Questions","description":"Use Google to find the answers to these five questions: What is the weather today? What year was your favorite movie released? What is a good recipe for banana bread? Where is the nearest library? How do you remove a coffee stain? Write down each answer.","type":"hands-on"},{"title":"Spot the Ads","description":"Search for best walking shoes and look at the results page. Identify which results are advertisements and which are real recommendations. Count how many ads you can spot. Talk about how you can tell the difference.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about searching the internet effectively using Google. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 3, 'Email Basics', 'Setting Up Email, Sending, Receiving, and Attachments', 'This class teaches you how to use email to send and receive messages. You''ll learn how to set up a free email account, write and send a message, read messages you receive, and attach files like photos to your emails.', '[{"title":"What Is Email?","content":"Email is electronic mail. It works just like regular mail but instead of going to a mailbox outside, it goes to a mailbox on your computer or phone. It''s free, it''s fast, and it''s a great way to stay in touch with family and friends. You can send messages, photos, and documents to anyone in the world in just seconds."},{"title":"Setting Up a Free Email Account","content":"If you don''t have an email account yet, you can get one for free from Gmail (Google), Outlook (Microsoft), or Yahoo. We''ll walk through setting one up step by step. You''ll pick an email address (like yourname@gmail.com), create a password, and answer a few simple questions. Write down your email address and password somewhere safe."},{"title":"Sending and Reading Emails","content":"To send an email, click the Compose or New Message button. Type the person''s email address in the To field, write a subject line (like a title for your message), and type your message in the big box below. Click Send and off it goes. To read emails, click on your Inbox. New messages will appear in bold. Click on a message to read it, just like opening an envelope."},{"title":"Attaching Files and Photos","content":"If you want to send a photo or a document with your email, use the attachment feature. Look for a paperclip icon when you are writing your email. Click it, find the file on your computer, select it, and click Open. The file will be attached to your message. This is great for sending photos of the grandkids or sharing documents."}]', '["Send an email to a specific person with a subject line and message","Read and reply to an email in the Inbox","Attach a file or photo to an outgoing email"]', '[{"title":"Send Your First Email","description":"Open your email account and write a message to a family member or friend. Include a greeting, a short message about what you learned today, and a nice closing. Add a subject line and press Send. Then check your Sent folder to confirm it went through.","type":"hands-on"},{"title":"Attach a Photo","description":"Write another email and this time attach a photo or the file you created in an earlier class. Click the paperclip icon, find the file, and attach it. Send it to yourself so you can practice opening an attachment too.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about email basics including sending, receiving, and attachments. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 4, 'Video Calling Family and Friends', 'Zoom, FaceTime, and Google Meet Basics', 'This class teaches you how to make video calls so you can see and talk to your family and friends face to face through your computer or phone. You''ll learn how to set up and use popular video calling apps like Zoom, FaceTime, and Google Meet.', '[{"title":"What Is a Video Call?","content":"A video call lets you see and talk to someone in real time through your computer or phone screen. It''s like a phone call where you can also see the other person''s face. It''s a wonderful way to stay connected with family members who live far away. You can see the grandkids smile, show someone your garden, or just chat face to face."},{"title":"Choosing a Video Calling App","content":"The most popular video calling tools are Zoom, FaceTime, and Google Meet. FaceTime works on Apple devices like iPhones and iPads. Google Meet works in your web browser and is free with a Google account. Zoom works on almost everything and is very popular. We''ll focus on whichever one works best for your device."},{"title":"Making Your First Video Call","content":"To start a video call, you open the app and either type in someone''s email address or click a link they sent you. Make sure your camera is on by checking for a little light near the camera. Speak normally. You''ll see yourself in a small box on the screen and the other person in the big box. If you can''t hear them, check your volume."},{"title":"Video Call Etiquette and Tips","content":"Find a spot with good lighting so the other person can see your face. Face a window if you can. Make sure the room is quiet. Look at the camera when you talk, not at the screen. When the call is over, click the red button to hang up. Don''t worry if it takes a few tries to get comfortable. Everyone was a beginner at this."}]', '["Open a video calling app and start or join a video call","Check that the camera and microphone are working before a call","End a video call properly using the hang-up button"]', '[{"title":"Test Your Camera and Microphone","description":"Open your video calling app and start a test call or preview. Make sure you can see yourself on screen and that the microphone is picking up your voice. Adjust the volume and camera angle until everything looks and sounds good.","type":"hands-on"},{"title":"Call a Friend or Family Member","description":"Schedule a short practice video call with a family member or friend. Open the app, start the call, and chat for a few minutes. Practice muting and unmuting yourself, and try ending the call with the red button.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about video calling using Zoom, FaceTime, or Google Meet. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 5, 'Using Word Processing', 'Writing Letters and Formatting Text', 'This class teaches you how to use a word processing program like Microsoft Word or Google Docs to write letters, notes, and other documents. You''ll learn how to type, format text to look nice, and save and print your work.', '[{"title":"What Is Word Processing?","content":"Word processing is just a fancy way of saying typing on a computer. Programs like Microsoft Word and Google Docs let you write letters, make lists, create signs, and much more. Think of it as a typewriter that lets you fix mistakes, change how things look, and save everything so you can come back to it later."},{"title":"Starting a New Document","content":"Open Microsoft Word or Google Docs. You''ll see a blank white page ready for you to type on. Just start typing. The cursor, that blinking line, shows you where your next letter will appear. Press Enter to start a new line. Press the space bar to add spaces between words. Take your time and type at whatever speed feels comfortable."},{"title":"Making Your Text Look Nice","content":"You can change how your text looks using formatting. Select the text you want to change by clicking at the start, holding the mouse button, and dragging to the end. Then you can make it bold (thicker and darker), italic (slanted), or underlined using the buttons at the top. You can also change the size to make text bigger or smaller, and change the font to use different styles of lettering."},{"title":"Saving and Printing Your Document","content":"When you are happy with what you wrote, save it by clicking File then Save. Give it a name you''ll remember. To print it, click File then Print, choose your printer, and click Print. Now you have a beautiful document that you typed all by yourself. You can also email it to someone or just keep it for your records."}]', '["Type a short letter or note in a word processing program","Format text by making it bold, changing the size, or changing the font","Save the document and print it if a printer is available"]', '[{"title":"Write a Letter","description":"Open Microsoft Word or Google Docs and write a short letter to a friend or family member. Include a greeting, a few sentences about your day, and a closing. Save it with a clear name like Letter to Sarah.","type":"hands-on"},{"title":"Make It Fancy","description":"Go back to your letter and make the greeting bold and a little bigger. Change the font of the whole letter to something you like. Center your name at the bottom. Save the changes and print it if you can.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about word processing and writing documents on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 6, 'Working with Photos on Your Computer', 'Viewing, Organizing, and Simple Editing', 'This class teaches you how to view, organize, and do simple edits to photos on your computer. You''ll learn how to find your photos, put them in folders, and make simple improvements like cropping and brightening.', '[{"title":"Finding Your Photos","content":"Photos on your computer are usually stored in a folder called Pictures. You can find it by opening File Explorer and clicking on Pictures in the left side panel. If someone emailed you photos or you downloaded them from the internet, they might be in your Downloads folder instead. Let''s look in both places and see what you have."},{"title":"Viewing and Organizing Photos","content":"To look at a photo, just double-click on it and it will open up big on your screen. You can use arrow keys to flip through them like a photo album. To keep things organized, create folders inside your Pictures folder, like Grandkids, Vacation, and Garden. Then drag your photos into the right folders, just like putting prints into different albums."},{"title":"Simple Photo Editing","content":"You don''t need to be an expert to make your photos look better. Most computers come with a basic photo editor. Open a photo, then look for an Edit button. You can crop a photo to cut out parts you don''t want, brighten it if it''s too dark, or rotate it if it''s sideways. These small changes can make a big difference."},{"title":"Sharing Your Photos","content":"Once your photos look good, you can share them. You can email them to family, print them out to put on the fridge, or save them to a USB drive to give to someone. We''ll cover how to attach photos to an email, which you learned about in the email class, and how to print a nice copy of your favorite photo."}]', '["Find and view photos stored on the computer","Organize photos into named folders","Make a simple edit to a photo like cropping or brightening"]', '[{"title":"Organize Your Photos","description":"Open your Pictures folder and create two new folders with names that make sense to you, like Family and Nature. Move at least three photos into the right folders. If you don''t have photos yet, download a couple from the internet to practice with.","type":"hands-on"},{"title":"Edit a Photo","description":"Open one of your photos in the built-in photo editor. Try cropping it to focus on the most important part. Then try adjusting the brightness. Save the edited version and compare it to the original.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about viewing, organizing, and editing photos on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 7, 'Online Shopping Safely', 'Creating Accounts, Making Purchases, and Recognizing Scams', 'This class teaches you how to shop online safely and confidently. You''ll learn how to create an account on a shopping website, find and purchase items, and protect yourself from scams and fraud.', '[{"title":"Why Shop Online?","content":"Online shopping lets you buy things from the comfort of your home without driving anywhere. You can compare prices, read reviews from other shoppers, and have items delivered right to your door. It''s especially handy for things that are hard to find locally, or when it''s difficult to get to the store. Millions of people shop online safely every day."},{"title":"Creating an Account and Browsing","content":"Most shopping websites like Amazon or Walmart ask you to create a free account. You''ll enter your name, email address, and create a password. Once you are logged in, you can search for items using the search bar, just like searching on Google. Browse the results, look at photos, read descriptions, and check reviews from other buyers."},{"title":"Making a Purchase Safely","content":"When you find something you want, click Add to Cart. When you are ready to buy, go to your cart and click Checkout. You''ll enter your shipping address and payment information. Look for a little padlock icon in the address bar, which means the website is secure. Only shop on websites you trust. Never enter your credit card information on a website that doesn''t look right."},{"title":"Recognizing Scams and Protecting Yourself","content":"If a deal seems too good to be true, it probably is. Watch out for emails or pop-ups saying you won a prize or offering huge discounts from unknown companies. Only shop on well-known websites. Never click links in unexpected emails asking for payment information. Use a credit card instead of a debit card for extra protection. When in doubt, ask someone you trust before buying."}]', '["Search for and find a specific item on an online shopping website","Identify the signs that a website is secure before entering payment information","Recognize at least three common online shopping scams"]', '[{"title":"Window Shopping Online","description":"Go to a well-known shopping website like Amazon. Search for something you might want, like a book or a kitchen gadget. Read the description, check the reviews, and look at the price. Add it to your cart but do not buy it yet. This is just practice.","type":"hands-on"},{"title":"Scam Spotter","description":"Look at three example emails or websites (provided by the instructor) and decide which ones are real and which ones are scams. Talk about what clues gave them away, like strange web addresses, spelling mistakes, or deals that are too good to be true.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about online shopping safely. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 8, 'Streaming Music and Videos', 'YouTube, Netflix, and Spotify Basics', 'This class introduces you to streaming, which means watching videos and listening to music through the internet. You''ll learn how to use popular services like YouTube, Netflix, and Spotify to enjoy entertainment on your computer.', '[{"title":"What Is Streaming?","content":"Streaming means watching or listening to something over the internet without having to download the whole thing first. It''s like turning on a TV channel or a radio station, except you get to pick exactly what you want to watch or listen to, whenever you want. No schedule, no waiting. It comes right to your screen."},{"title":"Watching Videos on YouTube","content":"YouTube is a free website where you can watch millions of videos. Open your browser and go to www.youtube.com. Use the search bar at the top to look for anything, like how to make apple pie, Frank Sinatra, or funny cat videos. Click on a video to watch it. You can pause it, make it louder, or make it full screen using the buttons at the bottom of the video."},{"title":"Watching Movies and Shows on Netflix","content":"Netflix is a service that lets you watch movies and TV shows for a monthly fee. If you have an account, go to www.netflix.com and sign in. You can browse by category or search for something specific. Click on a show or movie to start watching. You can pause, rewind, and pick up where you left off next time. It''s like having a video store in your living room."},{"title":"Listening to Music with Spotify","content":"Spotify lets you listen to almost any song you can think of. You can use it for free with some ads or pay for no interruptions. Go to www.spotify.com or open the app. Search for a song, artist, or type of music you like. Click play and enjoy. You can also create playlists, which are like making your own mixtapes of your favorite songs."}]', '["Find and play a video on YouTube using the search feature","Navigate a streaming service like Netflix to find and watch something","Search for and play a song or artist on Spotify"]', '[{"title":"YouTube Explorer","description":"Go to YouTube and search for a song you loved when you were younger. Play it and practice using the pause, volume, and full screen buttons. Then search for a how-to video about something you are curious about, like a recipe or a craft.","type":"hands-on"},{"title":"Build a Playlist","description":"If you have access to Spotify or a similar music service, search for five songs you enjoy and add them to a new playlist. Give your playlist a fun name. Play it from start to finish and enjoy your own personal radio station.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about streaming music and videos using YouTube, Netflix, and Spotify. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 9, 'Managing Passwords Safely', 'Creating Strong Passwords and Using Password Managers', 'This class teaches you how to create passwords that are hard for others to guess and how to keep track of all your passwords safely. You''ll learn what makes a good password, common mistakes to avoid, and how a password manager can help.', '[{"title":"Why Passwords Matter","content":"Passwords are like the keys to your house but for your online accounts. Just like you wouldn''t leave your front door unlocked, you don''t want weak passwords on your email, bank, or shopping accounts. A good password keeps your personal information safe from people who shouldn''t have it. Let''s learn how to make strong ones."},{"title":"Creating a Strong Password","content":"A strong password is long, uses a mix of letters, numbers, and symbols, and is not easy to guess. Avoid using your name, birthday, or common words like password or 123456. A great trick is to think of a sentence and use the first letter of each word plus a number and symbol. For example, I Love My 3 Grandkids! becomes ILM3G! and you can make it longer from there."},{"title":"Common Password Mistakes","content":"Using the same password for everything is very risky. If someone figures out one password, they''ll have access to all your accounts. Writing passwords on sticky notes attached to your computer is also not safe. Never share your passwords with strangers, and never type them into a website that was linked from a suspicious email."},{"title":"Using a Password Manager","content":"A password manager is like a secure notebook that remembers all your passwords for you. You only have to remember one main password to unlock it. Popular ones include the one built into your web browser, as well as apps like LastPass or 1Password. It can even create strong passwords for you. It''s like having a super-secure filing cabinet for all your keys."}]', '["Create a strong password using the sentence method","Explain why using the same password for every account is risky","Set up or use a password manager to store a password safely"]', '[{"title":"Create Three Strong Passwords","description":"Using the sentence method we learned, create three strong passwords on a piece of paper. Each one should be different and at least 10 characters long. Check them against the rules: Does it have uppercase and lowercase letters? Numbers? Symbols? Then pick one to use for a real account.","type":"hands-on"},{"title":"Explore a Password Manager","description":"Open the password manager built into your web browser (Chrome, Edge, or Firefox all have one). Look at how it stores passwords. Try saving a new password in it when you log in to a website. Notice how it offers to fill in your password automatically next time.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about creating and managing passwords safely. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 20);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 10, 'Installing and Updating Software', 'How to Safely Install Apps and Keep Things Updated', 'This class teaches you how to safely add new programs to your computer and keep them up to date. You''ll learn where to find trustworthy software, how to install it, and why updates are important for keeping your computer safe and running well.', '[{"title":"What Are Software Updates and Why Do They Matter?","content":"Software updates are improvements that the people who made your programs send out over time. They fix problems, add new features, and most importantly, they patch security holes that bad guys might try to exploit. Think of it like getting your car serviced. You want to keep everything in good working order. When your computer says an update is available, it''s a good idea to install it."},{"title":"Updating Windows and Your Programs","content":"Your computer will usually tell you when updates are available. You might see a notification or a little icon. For Windows updates, go to Settings, then Update and Security, and click Check for Updates. For programs like your browser, look in the program''s menu for About or Check for Updates. These updates usually take a few minutes and may require a restart."},{"title":"Installing New Programs Safely","content":"If you want to add a new program, like a video calling app, always download it from the official website or the Microsoft Store. Never download programs from pop-up ads or emails from people you don''t know. When installing, read each screen carefully before clicking Next. Watch out for checkboxes that try to install extra programs you didn''t ask for. Uncheck those."},{"title":"Removing Programs You Don''t Need","content":"If you have programs you never use, you can remove them to free up space and keep things tidy. Go to Settings, then Apps, and you''ll see a list of everything installed. Click on a program you want to remove and choose Uninstall. It''s like cleaning out a closet. You only want to keep the things you actually use."}]', '["Check for and install Windows updates through the Settings menu","Download and install a program safely from an official source","Remove a program you no longer need using the Settings menu"]', '[{"title":"Check for Updates","description":"Go to Settings, then Update and Security (or Windows Update), and click Check for Updates. If any updates are available, install them. Also open your web browser and check if it has any updates available in its menu. Write down what updates you installed today.","type":"hands-on"},{"title":"Install and Uninstall Practice","description":"Go to the Microsoft Store and download a free app like a weather app or a simple game. Watch the installation process and open the app once it is installed. Then go to Settings, then Apps, find the app you just installed, and uninstall it for practice.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about installing and updating software on a computer. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 1, 'Social Media for Beginners', 'Facebook Basics and Connecting with Family', 'This class introduces you to social media, specifically Facebook, which is a great way to stay connected with family and friends. You''ll learn how to set up a profile, find people you know, and share updates and photos.', '[{"title":"What Is Social Media?","content":"Social media is a way to connect with people through the internet. Think of it like a community bulletin board where everyone can post updates, share photos, and leave comments. Facebook is the most popular one for keeping in touch with family and friends. It''s free to use and millions of people of all ages are on it, including your family members."},{"title":"Setting Up Your Facebook Profile","content":"To join Facebook, go to www.facebook.com and click Create New Account. You''ll enter your name, email, birthday, and create a password. Once you are in, you can add a profile photo, which is like your picture in a phone book. This helps people recognize you and know they found the right person when they search for you."},{"title":"Finding and Adding Friends and Family","content":"Use the search bar at the top to look for people by name. When you find someone you know, click Add Friend. They''ll get a notification and can accept your request. Once you are connected, you can see their posts and they can see yours. Start by searching for your children, grandchildren, siblings, or close friends."},{"title":"Sharing Updates and Staying Safe","content":"To share something, click the box that says What''s on your mind? at the top of your page. Type a message or click the photo icon to share a picture. Your friends will see it in their feed. Be careful about what you share publicly. Go to your privacy settings and make sure your posts are only visible to friends, not everyone. Never share your address, phone number, or financial information on social media."}]', '["Create a Facebook account and set up a basic profile with a photo","Find and send friend requests to family members","Post a simple status update or share a photo on Facebook"]', '[{"title":"Build Your Profile","description":"Create your Facebook account or log in if you already have one. Add a profile photo, write a short bio about yourself, and add your hometown. Look through the settings to make sure your privacy is set to Friends Only.","type":"hands-on"},{"title":"Connect and Share","description":"Search for and send friend requests to at least three family members or friends. Then write your first post sharing something simple, like what you had for dinner or a photo of something nice you saw today.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about social media and Facebook basics. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 2, 'Protecting Yourself Online', 'Recognizing Scams, Phishing, and Safe Browsing', 'This class teaches you how to stay safe while using the internet. You''ll learn how to recognize scams and phishing attempts, protect your personal information, and browse the internet with confidence.', '[{"title":"Why Online Safety Matters","content":"The internet is a wonderful tool, but just like in real life, there are people out there who try to trick you. They might send fake emails, create fake websites, or call you pretending to be from a company you trust. The good news is that once you know what to look for, these tricks are easy to spot and avoid. Knowledge is your best protection."},{"title":"Recognizing Phishing Emails and Messages","content":"Phishing is when someone sends you a fake email or message pretending to be from a real company like your bank, Amazon, or the government. They want you to click a link and enter your personal information. Warning signs include unexpected emails about account problems, urgent language like act now or your account will be closed, spelling mistakes, and email addresses that don''t look right. When in doubt, don''t click. Call the company directly instead."},{"title":"Safe Browsing Habits","content":"When you visit websites, look for the padlock icon in the address bar, which means the site is secure. Don''t click on pop-up ads or download anything from websites you don''t recognize. If a website asks for personal information, make sure you went there on purpose by typing the address yourself. Avoid clicking links in emails or text messages from people you don''t know."},{"title":"What to Do If You Think You Have Been Scammed","content":"If you accidentally clicked on something suspicious or gave out personal information, don''t panic. Change your passwords immediately for any affected accounts. Call your bank if you shared financial information. Tell a family member or friend what happened so they can help. You can also report scams to the Federal Trade Commission at reportfraud.ftc.gov. Remember, it is not your fault. These scammers are professionals."}]', '["Identify at least three warning signs of a phishing email","Check whether a website is secure before entering personal information","Know the steps to take if you suspect you have been scammed"]', '[{"title":"Phishing Email Detective","description":"Look at five example emails (provided by the instructor) and decide which ones are real and which are phishing scams. Write down the clues that helped you decide, like the sender''s address, the tone, and any suspicious links. Discuss your findings.","type":"hands-on"},{"title":"Safe Browsing Check","description":"Open your web browser and visit three websites. For each one, check for the padlock icon in the address bar. Look at the web address carefully. Note whether each site looks trustworthy and why. Practice typing a web address directly instead of clicking a link.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about protecting themselves online from scams and phishing. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 30);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 3, 'Cloud Storage Made Simple', 'Google Drive, Saving Files Online, and Accessing Them Anywhere', 'This class introduces you to cloud storage, which lets you save your files on the internet so you can access them from any computer or device. You''ll learn how to use Google Drive to store, organize, and share your files safely.', '[{"title":"What Is the Cloud?","content":"The cloud is just a way of saying your files are stored on the internet instead of just on your computer. Think of it like a safe deposit box at the bank. Your stuff is stored securely somewhere else, and you can go get it whenever you need it. The best part is that you can access your files from your computer, your phone, or anyone else''s computer just by logging in."},{"title":"Getting Started with Google Drive","content":"Google Drive is a free service that gives you storage space on the internet. If you have a Gmail account, you already have Google Drive. Go to drive.google.com and sign in with your Google account. You''ll see a clean, simple screen where you can upload files, create folders, and organize your stuff. It works just like the folders on your computer."},{"title":"Uploading and Organizing Files","content":"To put a file in Google Drive, click the New button and then File Upload. Find the file on your computer and click Open. It will be copied to your Drive. You can create folders by clicking New then Folder. Drag files into folders to keep things tidy. Everything you upload is automatically saved and backed up, so even if your computer breaks, your files are safe."},{"title":"Sharing Files with Family","content":"One of the nicest things about Google Drive is sharing. You can share a photo album with your grandkids or a document with a family member. Right-click on a file or folder and choose Share. Type in the person''s email address, and they''ll be able to see it too. You can choose whether they can just look at it or also make changes. It''s like letting someone into your safe deposit box."}]', '["Upload a file from the computer to Google Drive","Create a folder in Google Drive and organize files into it","Share a file or folder with a family member by email"]', '[{"title":"Upload Your Files","description":"Go to drive.google.com and sign in. Upload at least three files from your computer, like a letter you wrote, a photo, and a list. Create a folder called My Important Files and move them into it.","type":"hands-on"},{"title":"Share with Family","description":"Pick one of the files you uploaded and share it with a family member by entering their email address. Choose the option that lets them view but not edit. Ask them to confirm they can see it. This is a great way to share photos or documents without email attachments.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about cloud storage and Google Drive. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 4, 'Using Your Phone and Computer Together', 'Syncing Photos, Contacts, and Shared Apps', 'This class teaches you how your phone and computer can work together. You''ll learn how to move photos between devices, keep your contacts in sync, and use the same apps on both so everything stays connected.', '[{"title":"Your Devices Can Talk to Each Other","content":"Your phone and your computer don''t have to be separate worlds. They can work together so that a photo you take on your phone shows up on your computer, and a contact you add on your computer shows up on your phone. This is called syncing, which just means they share information automatically. It''s like having the same address book in your kitchen and your car."},{"title":"Syncing Photos Between Your Phone and Computer","content":"If you use an iPhone, iCloud can automatically save your photos to your computer. If you use an Android phone, Google Photos does the same thing. You can also plug your phone into your computer with a charging cable and copy photos over manually, like plugging in a camera. Either way, the goal is to get your phone photos somewhere safe where you can see them on a bigger screen."},{"title":"Keeping Contacts in Sync","content":"When you add a new phone number to your phone, it can automatically appear on your computer and other devices too. If you use a Google account on your phone, your contacts are already saved online at contacts.google.com. If you use an iPhone, your contacts sync through iCloud. This means you''ll never lose your phone numbers, even if you lose your phone."},{"title":"Using the Same Apps on Both Devices","content":"Many apps work on both your phone and your computer. For example, if you use Gmail on your phone, you can also check your email on your computer at gmail.com. The same goes for Google Drive, Facebook, and many other apps. Sign in with the same account on both devices, and your information will be the same everywhere. It''s like having the same key open two doors."}]', '["Set up photo syncing between a phone and computer using iCloud or Google Photos","Verify that contacts are synced between phone and computer","Access the same app or service on both a phone and a computer"]', '[{"title":"Photo Sync Check","description":"Take a photo on your phone. Then check your computer to see if it appeared automatically in iCloud Photos or Google Photos. If not, we''ll set up the syncing step by step. Try also plugging your phone in with a cable and copying a photo over manually.","type":"hands-on"},{"title":"Same Account, Two Devices","description":"Pick an app you use on your phone, like Gmail or Google Drive. Open the same service on your computer in a web browser and sign in with the same account. Check that you see the same emails, files, or contacts on both devices. Notice how changes on one show up on the other.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about using their phone and computer together, including syncing photos and contacts. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 5, 'Online Banking and Bill Pay', 'Safety Tips, Setting Up Accounts, and Paying Bills Online', 'This class teaches you how to use online banking safely to check your accounts and pay bills from your computer. You''ll learn how to set up online access, navigate your bank''s website, and protect your financial information.', '[{"title":"Why Online Banking?","content":"Online banking lets you check your account balance, see recent transactions, and pay bills without driving to the bank or mailing checks. It''s available anytime day or night, and it saves you stamps and trips. Your bank uses very strong security to protect your money, and we''ll learn how to add your own layer of protection too."},{"title":"Setting Up Online Banking","content":"Most banks let you sign up for online banking on their website. Go to your bank''s website (the real one, not a link from an email) and look for a button that says Sign Up, Register, or Enroll. You''ll need your account number, Social Security number for verification, and you''ll create a username and strong password. Write this information down and keep it in a safe place at home, not on your computer."},{"title":"Checking Your Accounts and Paying Bills","content":"Once you are logged in, you can see your account balance and a list of recent transactions, like a digital version of your bank statement. To pay a bill, look for a section called Bill Pay or Payments. You can add the companies you pay regularly, like your electric company or phone company, and schedule payments. Some banks even let you set up automatic payments so you never miss a due date."},{"title":"Staying Safe with Online Banking","content":"Always type your bank''s web address directly into the browser. Never click a link from an email that says it''s from your bank. Log out when you are done, especially on a shared computer. Enable two-factor authentication if your bank offers it, which means they''ll send a code to your phone as an extra check. If anything looks strange on your account, call your bank right away using the number on the back of your card."}]', '["Log in to online banking and check an account balance","Navigate to the bill pay section and understand how to set up a payment","Identify three safety practices for online banking"]', '[{"title":"Explore Your Online Banking","description":"Log in to your bank''s website (or set up online access if you haven''t yet). Find your account balance and look at your recent transactions. Navigate to the bill pay section and see what options are available. Do not make any payments yet; this is just exploration.","type":"hands-on"},{"title":"Security Checkup","description":"While logged in, find the security settings in your online banking account. Check if two-factor authentication is turned on. Review your contact information to make sure it''s current. Practice logging out properly when you are done. Make sure you''re typing the bank''s address directly and not using a bookmarked link you''re unsure about.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about online banking and bill pay. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 30);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 6, 'Telehealth and Online Appointments', 'Video Doctor Visits and Patient Portals', 'This class teaches you how to visit your doctor through a video call and use patient portals to manage your health information online. You''ll learn how to prepare for a telehealth visit and access your medical records from home.', '[{"title":"What Is Telehealth?","content":"Telehealth means visiting your doctor through a video call on your computer or phone instead of going to the office in person. It''s great for follow-up appointments, quick questions, prescription refills, and times when it''s hard to get to the office. You still talk to your real doctor, you just do it from the comfort of your living room. It became very popular and is now a normal part of healthcare."},{"title":"Preparing for a Telehealth Visit","content":"Before your appointment, make sure your computer''s camera and microphone work. Sit in a well-lit, quiet room. Have your list of medications nearby and write down any questions you want to ask. Your doctor''s office will usually send you a link by email or text message. Click the link at the appointment time and your video visit will start. It''s very similar to a Zoom call."},{"title":"Using a Patient Portal","content":"A patient portal is a secure website where you can see your medical information. Most doctor''s offices and hospitals have one, like MyChart or similar systems. You can view test results, see upcoming appointments, request prescription refills, and send messages to your doctor. Ask your doctor''s office how to sign up. They''ll give you a username or help you create an account."},{"title":"Making the Most of Online Health Tools","content":"You can use your patient portal to prepare for visits by reviewing your medical history. After a visit, check the portal for any notes your doctor left or instructions they gave you. You can also set up medication reminders on your phone. These tools help you take charge of your health and stay organized. Remember, your health information is private and protected by law."}]', '["Join a telehealth video appointment using a link from the doctor''s office","Log in to a patient portal and find upcoming appointments or test results","Prepare a list of questions and medications before a telehealth visit"]', '[{"title":"Telehealth Test Run","description":"Practice the steps for joining a video call. Open your browser, check that your camera shows your face, and test your microphone and speakers. If your doctor''s office has a test link, try it. Write down the steps so you feel confident on appointment day.","type":"hands-on"},{"title":"Explore Your Patient Portal","description":"Log in to your patient portal (like MyChart) or set up an account if you haven''t yet. Find your list of medications, your upcoming appointments, and your most recent test results. Try sending a non-urgent message to your doctor through the portal. Notice how everything is organized.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about telehealth and patient portals for managing health appointments online. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 30);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 7, 'Government Services Online', 'Social Security, Medicare, and DMV Online', 'This class teaches you how to access important government services from your computer without waiting in long lines. You''ll learn how to check your Social Security information, manage Medicare, and handle DMV tasks online.', '[{"title":"Why Use Government Websites?","content":"Many government services that used to require a trip to an office can now be done from your computer. You can check your Social Security benefits, review your Medicare coverage, renew your driver''s license, and much more, all without leaving home. These official websites are safe and secure, and they can save you a lot of time and trips."},{"title":"Social Security Online","content":"The Social Security Administration has a website at ssa.gov where you can create a my Social Security account. Once you have an account, you can check your benefit amount, download tax forms, change your address, and even set up or change direct deposit. To sign up, go to ssa.gov and click Create an Account. You''ll verify your identity with some personal information and set up a secure login."},{"title":"Medicare Online","content":"Medicare has a website at medicare.gov where you can manage your health coverage. Create an account or log in to see what your plan covers, find doctors in your network, check the status of claims, and compare plans during open enrollment. It''s like having your Medicare office on your computer. You can also call 1-800-MEDICARE if you need help with anything."},{"title":"DMV and Other Services","content":"Most states let you renew your driver''s license or ID, register your vehicle, and even schedule appointments online through your state''s DMV website. Search for your state DMV online to find the website. You can also pay property taxes, access court records, and find other local services online. Always make sure you are on the official government website (it usually ends in .gov) to keep your information safe."}]', '["Navigate to ssa.gov and find information about creating a my Social Security account","Access medicare.gov and explore what services are available","Find your state''s DMV website and identify at least two tasks you can do online"]', '[{"title":"Visit Government Websites","description":"Open your web browser and visit ssa.gov, medicare.gov, and your state''s DMV website. At each site, explore what services are available. Write down two things you could do on each website without going to an office. Check that each address ends in .gov to make sure it''s official.","type":"hands-on"},{"title":"Create or Log Into a Government Account","description":"Choose one government service, like my Social Security or Medicare, and either create an account or log in to an existing one. Explore the dashboard and find one useful piece of information, like your benefit amount or your coverage details. Take a screenshot or write it down for your records.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about accessing government services online like Social Security, Medicare, and the DMV. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 30);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 8, 'Troubleshooting Common Problems', 'Slow Computer, Frozen Screen, and No Internet', 'This class teaches you what to do when your computer isn''t working right. You''ll learn simple steps to fix the most common problems like a slow computer, a frozen screen, and internet connection issues.', '[{"title":"Don''t Panic, It Happens to Everyone","content":"Computers are not perfect, and every single person who uses one runs into problems sometimes. The good news is that the most common problems have simple solutions. You don''t need to be a computer expert. Most of the time, a few basic steps will get things working again. Think of this class as your emergency toolkit."},{"title":"Fixing a Slow Computer","content":"If your computer is running slowly, try these steps. First, close any programs you are not using. Having too many things open is like trying to carry too many grocery bags at once. Next, restart your computer, which clears things out and freshens it up. If it''s still slow, check if it''s installing updates in the background. You can also go to Settings, then Storage, and delete files you don''t need anymore, like emptying a full closet."},{"title":"What to Do When the Screen Freezes","content":"If your screen is frozen and nothing responds when you click or type, wait about 30 seconds first. Sometimes the computer is just thinking hard. If it''s still stuck, try pressing Ctrl plus Alt plus Delete at the same time. This brings up a special menu where you can open Task Manager and close the program that''s causing the problem. As a last resort, hold the power button down for about 10 seconds to force the computer to turn off, then turn it back on."},{"title":"Fixing Internet Connection Problems","content":"If the internet stops working, first check if other devices like your phone can connect. If nothing can connect, the problem is probably with your router, the little box that provides your internet. Unplug the router, wait 30 seconds, and plug it back in. Give it a couple of minutes to restart. If your phone works but your computer does not, click the Wi-Fi icon on your taskbar and make sure you are connected to your home network. If all else fails, call your internet provider."}]', '["Close unnecessary programs and restart the computer to fix slowness","Use Ctrl plus Alt plus Delete to handle a frozen screen","Troubleshoot a basic internet connection problem by resetting the router"]', '[{"title":"Speed Up Your Computer","description":"Check how many programs are currently open on your computer by looking at the taskbar. Close anything you are not actively using. Then restart your computer and notice if it feels faster when it comes back on. Check your storage to see how full your computer is.","type":"hands-on"},{"title":"Practice the Emergency Steps","description":"Practice pressing Ctrl plus Alt plus Delete to see the special menu (don''t worry, it won''t break anything). Look at the Task Manager and see which programs are running. Also, locate your Wi-Fi icon on the taskbar and practice disconnecting and reconnecting to your home network.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about troubleshooting common computer problems. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 9, 'Staying Connected with Technology', 'Texting, Messaging Apps, and Staying in Touch', 'This class shows you the many ways you can stay in touch with family and friends using your computer and phone. You''ll learn about text messaging, messaging apps like WhatsApp and Facebook Messenger, and how to choose the right way to reach out.', '[{"title":"So Many Ways to Stay in Touch","content":"There are more ways to communicate with people now than ever before. You can call, text, email, video chat, or use a messaging app. Each one has its strengths. A quick text for short messages, an email for longer ones, a video call when you want to see someone''s face. Let''s explore all your options so you can pick the best one for each situation."},{"title":"Text Messaging Basics","content":"Text messaging, also called texting, is sending a short written message from your phone. Open the Messages app on your phone, tap the person''s name, type your message, and hit Send. You can also send photos, videos, and even voice messages. Texting is great for quick check-ins like running late or thinking of you. You don''t need the internet for basic texts, just phone service."},{"title":"Messaging Apps Like WhatsApp and Messenger","content":"Messaging apps are like texting, but they work over the internet and have extra features. WhatsApp is popular for keeping in touch with family, especially internationally, because it''s free worldwide. Facebook Messenger lets you chat with your Facebook friends. Both let you send messages, photos, voice messages, and make video calls. You can use them on your phone and your computer."},{"title":"Choosing the Right Way to Connect","content":"Here''s a simple guide: For a quick question or hello, send a text or a message through an app. For something longer or more detailed, send an email. For when you want to see someone''s face and have a real conversation, make a video call. For sharing lots of photos, use a messaging app or email. The most important thing is not which method you use, but that you reach out. Your family and friends love hearing from you."}]', '["Send a text message from a phone including a photo","Use a messaging app like WhatsApp or Facebook Messenger to send a message","Choose the best communication method for different situations"]', '[{"title":"Message Someone You Love","description":"Pick a family member or friend and send them a text message from your phone. Include a short greeting and a photo, like a picture of what you see outside your window or your lunch. Then try sending them a message through a messaging app like WhatsApp or Facebook Messenger.","type":"hands-on"},{"title":"Communication Method Match","description":"Think of five situations: wishing someone happy birthday, sharing vacation photos, asking what time dinner is, having a long catch-up conversation, and sending someone a document. For each one, decide whether you would text, email, use a messaging app, or make a video call. Discuss your choices.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about staying connected with family and friends through texting and messaging apps. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 25);
INSERT INTO cb_classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 10, 'Keeping Your Computer Healthy', 'Updates, Antivirus, Cleaning Up, and Backups', 'This final class teaches you how to take care of your computer so it stays fast, safe, and reliable for years to come. You''ll learn about regular maintenance tasks like updates, antivirus protection, cleaning up old files, and backing up your important data.', '[{"title":"Your Computer Needs Regular Care","content":"Just like a car needs oil changes and a house needs cleaning, your computer needs regular maintenance to keep running well. The good news is that computer maintenance is much easier than car maintenance. A few simple habits will keep your computer healthy, fast, and safe. Think of this as your computer care routine, like brushing your teeth but for your computer."},{"title":"Keeping Everything Updated","content":"Updates are improvements and security fixes that come out regularly. Windows updates protect your computer from new threats and fix problems. To check for updates, go to Settings, then Windows Update, and click Check for Updates. It''s best to let these install and restart your computer when asked. Also keep your web browser and other programs updated. Think of updates as getting a flu shot for your computer."},{"title":"Antivirus Protection","content":"Antivirus software protects your computer from harmful programs called viruses and malware. Windows comes with built-in protection called Windows Security (or Windows Defender). Make sure it''s turned on by going to Settings, then Privacy and Security, then Windows Security. It runs in the background and checks for threats automatically. You don''t need to buy extra antivirus software in most cases. The built-in one does a good job."},{"title":"Cleaning Up and Backing Up","content":"Over time, your computer collects files you don''t need, like temporary files and things in the recycle bin. Go to Settings, then Storage, and use the cleanup tools to free up space. For backing up, this means making a copy of your important files in case something goes wrong. You can back up to a USB drive or use cloud storage like Google Drive. Think of it like making photocopies of important documents and keeping them in a safe place. Do this once a month and you''ll be in great shape."}]', '["Check for and install Windows updates on a regular schedule","Verify that Windows Security is turned on and running","Perform a basic cleanup of unnecessary files and create a backup of important documents"]', '[{"title":"Monthly Maintenance Checklist","description":"Go through a complete maintenance routine: Check for Windows updates and install any that are available. Open Windows Security and make sure protection is turned on and there are no alerts. Go to Storage settings and run the cleanup tool to free up space. Empty the recycle bin. Write down today''s date as your last maintenance day.","type":"hands-on"},{"title":"Back Up Your Important Files","description":"Identify five important files on your computer, like letters, photos, or lists. Copy them to a USB drive or upload them to Google Drive. Verify that the copies are there by opening them from the backup location. Set a reminder on your calendar to do this once a month going forward.","type":"hands-on"}]', 'You are a patient, friendly computer tutor named Agent Zero helping an older adult learn about keeping their computer healthy through updates, antivirus, cleanup, and backups. Use very simple language, avoid jargon, give step-by-step instructions, and be very encouraging. If they seem confused, offer to explain in a different way. Relate concepts to things they already know from everyday life.', 30);
